// BATCH 22 — TPS VERBAL 200 SOAL HOTS (Grade 12 - Entry Undergraduate)
appendQuestions('tps_verbal', [
// --- ANALOGI TINGKAT TINGGI (1-40) ---
{question:"KATALIS : REAKSI :: STIMULUS : ...",options:["Respons","Refleks","Insting","Habituasi","Adaptasi"],answer:0,hint:"Katalis mempercepat reaksi. Stimulus memicu respons.",explanation:"Katalis mempercepat reaksi kimia tanpa ikut bereaksi.\nStimulus memicu/mempercepat respons (tanggapan) dari organisme.\nHubungan: pemicu -> hasil.\nJawaban: A."},
{question:"EPILOG : NOVEL :: KODA : ...",options:["Musik","Puisi","Film","Drama","Lukisan"],answer:0,hint:"Epilog = bagian penutup novel. Koda = bagian penutup komposisi musik.",explanation:"Epilog: bagian akhir/penutup karya sastra (novel).\nKoda: bagian penutup komposisi musik.\nAnalogi fungsi: penutup karya.\nJawaban: A."},
{question:"HIPERBOLA : BERLEBIHAN :: LITOTES : ...",options: ["Merendahkan/mengecilkan","Menyindir (berdasarkan acuan formal)","Membandingkan (pada dasarnya)","Mempertentangkan (di konteks ini)","Mengulang (dalam batasan konvensional)"],answer:0,hint:"Hiperbola melebih-lebihkan. Litotes mengecilkan.",explanation:"Hiperbola: gaya bahasa melebih-lebihkan.\nLitotes: gaya bahasa merendahkan/mengecilkan kenyataan.\nJawaban: A."},
{question:"AMNESIA : INGATAN :: AFASIA : ...",options: ["Kemampuan berbicara/berbahasa","Penglihatan (dari sudut pandang klasik)","Pendengaran (dalam literatur standar)","Gerakan (menurut pandangan mainstream)","Emosi (dalam pengertian luas)"],answer:0,hint:"Amnesia = gangguan ingatan. Afasia = gangguan bahasa.",explanation:"Amnesia: kehilangan/gangguan memori.\nAfasia: kehilangan/gangguan kemampuan berbahasa (bicara/memahami).\nJawaban: A."},
{question:"PALEONTOLOGI : FOSIL :: ARKEOLOGI : ...",options: ["Artefak peninggalan manusia purba","Bintang (menurut definisi standar)","Cuaca (menurut pengertian baku)","Laut (sesuai paradigma tradisional)","Gunung berapi (menurut prinsip dasar)"],answer:0,hint:"Paleontologi mempelajari fosil. Arkeologi mempelajari artefak manusia.",explanation:"Paleontologi: ilmu yang mempelajari fosil makhluk hidup purba.\nArkeologi: ilmu yang mempelajari artefak/peninggalan budaya manusia purba.\nJawaban: A."},
{question:"SIMBIOSIS : ORGANISME :: DIPLOMASI : ...",options:["Negara","Individu","Sel","Atom","Molekul"],answer:0,hint:"Simbiosis = hubungan antar organisme. Diplomasi = hubungan antar negara.",explanation:"Simbiosis: hubungan timbal balik antara organisme.\nDiplomasi: hubungan/negosiasi antara negara.\nAnalogi: jenis hubungan antara entitas.\nJawaban: A."},
{question:"BAROMETER : TEKANAN :: HIGROMETER : ...",options:["Kelembapan udara","Suhu","Kecepatan angin","Curah hujan","Intensitas cahaya"],answer:0,hint:"Barometer mengukur tekanan udara. Higrometer mengukur kelembapan.",explanation:"Barometer: alat ukur tekanan atmosfer.\nHigrometer: alat ukur kelembapan udara.\nJawaban: A."},
{question:"ABSTRAK : KONKRET :: TEORITIS : ...",options: ["Empiris/praktis","Analitis (dalam teori)","Sintetis (pada prinsipnya)","Deduktif (menurut standar)","Induktif (secara literal)"],answer:0,hint:"Abstrak >< konkret. Teoritis >< empiris.",explanation:"Abstrak lawan konkret (nyata/berwujud).\nTeoritis lawan empiris/praktis (berdasarkan pengalaman/pengamatan langsung).\nJawaban: A."},
{question:"MONOGAMI : SATU :: POLIGAMI : ...",options: ["Banyak (lebih dari satu pasangan)","Dua (dalam konteks umum; berdasarkan teori dasar)","Tiga (berdasarkan referensi umum)","Tidak ada (menurut kerangka berpikir umum)","Semua (sesuai teori klasik)"],answer:0,hint:"Mono=satu. Poli=banyak. -gami=pernikahan.",explanation:"Monogami: pernikahan dengan satu pasangan.\nPoligami: pernikahan dengan lebih dari satu pasangan.\nMono=satu, poli=banyak.\nJawaban: A."},
{question:"EROSI : TANAH :: KOROSI : ...",options:["Logam","Air","Udara","Kayu","Plastik"],answer:0,hint:"Erosi = pengikisan tanah. Korosi = pengikisan/karat logam.",explanation:"Erosi: pengikisan tanah oleh air/angin.\nKorosi: pengikisan/perusakan logam oleh reaksi kimia (karat).\nJawaban: A."},
// --- SILOGISME & LOGIKA VERBAL (11-30) ---
{question:"Semua mahasiswa wajib mengikuti KKN. Budi adalah mahasiswa. Kesimpulan yang SAH: ...",options:["Budi wajib mengikuti KKN","Budi sudah mengikuti KKN","KKN wajib untuk semua orang","Budi bukan mahasiswa jika tidak KKN","Tidak ada kesimpulan"],answer:0,hint:"All M are P. S is M. Therefore S is P.",explanation:"Premis mayor: Semua mahasiswa wajib KKN.\nPremis minor: Budi mahasiswa.\nKonklusi valid: Budi wajib KKN.\nJawaban: A."},
{question:"Tidak ada reptil yang bernapas dengan insang. Buaya adalah reptil. Kesimpulan: ...",options:["Buaya tidak bernapas dengan insang","Buaya bernapas dengan insang","Semua hewan bernapas dengan paru-paru","Reptil adalah amfibi","Insang hanya untuk ikan"],answer:0,hint:"No M are P. S is M. Therefore S is not P.",explanation:"No reptil bernapas insang.\nBuaya = reptil.\nMaka buaya tidak bernapas insang.\nJawaban: A."},
{question:"'Jika hujan, maka jalan basah. Jalan tidak basah.' Kesimpulan dengan modus tollens: ...",options:["Tidak hujan","Hujan","Jalan basah","Mungkin hujan","Tidak ada kesimpulan"],answer:0,hint:"Modus tollens: If P then Q. Not Q. Therefore not P.",explanation:"P -> Q (hujan -> jalan basah).\nNot Q (jalan tidak basah).\nModus tollens: Not P (tidak hujan).\nJawaban: A."},
{question:"'Semua yang rajin belajar lulus ujian. Ani tidak lulus ujian.' Kesimpulan: ...",options: ["Ani tidak rajin belajar","Ani rajin belajar (secara teknis)","Ujian terlalu sulit","Ani sakit (secara konvensional)","Tidak ada hubungan (di konteks ini)"],answer:0,hint:"All P are Q. Not Q. Therefore not P (modus tollens).",explanation:"Rajin -> lulus.\nAni tidak lulus (not Q).\nModus tollens: Ani tidak rajin (not P).\nJawaban: A."},
{question:"'Jika harga naik, permintaan turun. Harga naik.' Kesimpulan: ...",options:["Permintaan turun","Permintaan naik","Harga turun","Tidak ada perubahan","Penawaran turun"],answer:0,hint:"Modus ponens: If P then Q. P. Therefore Q.",explanation:"P -> Q. P benar.\nModus ponens: Q benar (permintaan turun).\nJawaban: A."},
{question:"Pernyataan: 'Beberapa guru adalah peneliti.' Mana yang PASTI SALAH?",options:["Tidak ada guru yang peneliti","Semua peneliti adalah guru","Ada guru yang bukan peneliti","Ada peneliti yang bukan guru","Beberapa peneliti adalah guru"],answer:0,hint:"'Beberapa A adalah B' kontradiksi dengan 'Tidak ada A yang B'.",explanation:"'Beberapa guru adalah peneliti' = minimal 1 guru = peneliti.\nKontradiksi langsung: 'Tidak ada guru yang peneliti' (= 0 guru peneliti).\nYang pasti salah: A.\nJawaban: A."},
{question:"'Semua burung memiliki sayap. Penguin adalah burung. Penguin bisa terbang.' Yang TIDAK VALID: ...",options: ["Penguin bisa terbang (tidak mengikuti dari premis)","Penguin memiliki sayap (menurut kerangka berpikir umum)","Penguin adalah burung (sesuai teori klasik)","Semua burung punya sayap (berdasarkan premis dasar)","Tidak ada yang salah (secara terminologis)"],answer:0,hint:"Punya sayap =/= bisa terbang. Non sequitur.",explanation:"Dari 'semua burung punya sayap' dan 'penguin burung', hanya bisa disimpulkan 'penguin punya sayap'.\n'Bisa terbang' tidak mengikuti logisnya (non sequitur).\nJawaban: A."},
{question:"Diketahui: P -> Q, Q -> R, R -> S. Jika P benar, maka: ...",options: ["S benar (rantai implikasi transitif)","S salah (berdasarkan teori dasar)","Hanya Q benar (secara konseptual)","Hanya R benar (berdasarkan asumsi dasar)","Tidak ada kesimpulan (dalam kerangka teori)"],answer:0,hint:"Hypothetical syllogism: P->Q->R->S. If P, then S.",explanation:"Chain rule / hypothetical syllogism:\nP->Q, Q->R, R->S.\nP benar -> Q benar -> R benar -> S benar.\nJawaban: A."},
{question:"'Tidak semua politisi jujur' setara dengan: ...",options:["Ada politisi yang tidak jujur","Semua politisi tidak jujur","Tidak ada politisi yang jujur","Semua politisi jujur","Jujur bukan sifat politisi"],answer:0,hint:"'Tidak semua A adalah B' = 'Ada A yang bukan B'.",explanation:"'Tidak semua P jujur' = negasi dari 'semua P jujur'.\n= 'Ada P yang tidak jujur' (minimal satu).\nBukan berarti semua P bohong.\nJawaban: A."},
{question:"Kesalahan logika 'ad hominem' terjadi ketika: ...",options: ["Menyerang pribadi lawan, bukan argumennya","Menggunakan otoritas palsu (dalam definisi teknis)","Generalisasi terburu-buru (dalam konteks umum)","Mengalihkan topik (berdasarkan referensi umum)","Banding kasihan (menurut kerangka berpikir umum)"],answer:0,hint:"Ad hominem = 'terhadap orang'. Serang orangnya, bukan argumennya.",explanation:"Ad hominem: menyerang karakter/pribadi orang yang berargumen, bukan substansi argumennya.\nContoh: 'Kamu tidak bisa bicara tentang korupsi, kamu kan bukan pejabat.'\nJawaban: A."},
// --- PEMAHAMAN BACAAN KRITIS (21-50) ---
{question:"Paragraf: 'Energi terbarukan semakin penting karena cadangan fosil menipis dan dampak lingkungan yang semakin parah.' Gagasan utama: ...",options: ["Pentingnya energi terbarukan karena masalah energi fosil dan lingkungan","Cadangan fosil masih melimpah (secara normatif; dalam batasan konvensional)","Energi terbarukan tidak efisien (dari perspektif akademis)","Lingkungan tidak terpengaruh energi (sesuai klasifikasi umum)","Fosil lebih baik dari terbarukan (berdasarkan teori dasar)"],answer:0,hint:"Kata kunci: 'semakin penting karena...' = gagasan utama.",explanation:"Gagasan utama: pentingnya energi terbarukan.\nAlasan: (1) cadangan fosil menipis, (2) dampak lingkungan parah.\nJawaban: A."},
{question:"Bacaan: 'Meskipun vaksinasi menurunkan angka kematian secara drastis, sebagian masyarakat masih menolak karena informasi yang salah.' Pernyataan yang SESUAI: ...",options: ["Misinformasi menjadi faktor penolakan vaksinasi meskipun terbukti efektif","Vaksinasi tidak efektif (secara konvensional; dalam pengertian luas)","Semua orang menolak vaksinasi (pada konteks konvensional)","Informasi tentang vaksin selalu benar (dalam batasan konvensional)","Vaksinasi meningkatkan kematian (secara fundamental; berdasarkan referensi umum)"],answer:0,hint:"'Meskipun' = konsesi. Efektif tapi ditolak karena misinfo.",explanation:"Teks menyatakan: vaksinasi efektif (menurunkan kematian drastis) TAPI ditolak karena informasi salah.\nA paling sesuai.\nJawaban: A."},
{question:"'Korelasi tidak sama dengan kausalitas.' Contoh yang MELANGGAR prinsip ini: ...",options: ["Es krim laris, angka tenggelam naik, maka es krim menyebabkan tenggelam","Merokok menyebabkan kanker (terbukti riset) (dalam literatur standar)","Vaksin mencegah penyakit (uji klinis) (menurut pandangan mainstream)","Gravitasi menyebabkan benda jatuh (dalam pengertian luas)","Panas menyebabkan es mencair (dalam definisi teknis; sesuai klasifikasi umum)"],answer:0,hint:"Korelasi = bersamaan. Kausalitas = sebab-akibat. A hanya korelasi.",explanation:"Es krim dan tenggelam berkorelasi (keduanya naik di musim panas) tapi tidak kausal.\nConfounding variable: cuaca panas.\nIni contoh klasik korelasi =/= kausalitas.\nJawaban: A."},
{question:"Teks: 'Urbanisasi menyebabkan kepadatan, polusi, dan ketimpangan sosial di kota-kota besar Indonesia.' Kesimpulan IMPLISIT: ...",options: ["Perlu kebijakan untuk mengelola dampak negatif urbanisasi","Urbanisasi harus dihentikan total (menurut pengertian baku)","Kota kecil tidak memiliki masalah (sesuai paradigma tradisional)","Desa lebih baik dari kota (menurut prinsip dasar)","Polusi hanya ada di Jakarta (secara normatif)"],answer:0,hint:"Jika ada masalah, implikasi logisnya: perlu solusi/kebijakan.",explanation:"Teks menunjukkan dampak negatif urbanisasi.\nKesimpulan implisit: perlu kebijakan pengelolaan (bukan menghentikan total).\nJawaban: A."},
{question:"'Argumentum ad populum' adalah kesalahan logika berupa: ...",options: ["Menggunakan popularitas sebagai bukti kebenaran","Menyerang pribadi (berdasarkan premis dasar)","Menggunakan otoritas palsu (secara terminologis)","Generalisasi dari satu kasus (berdasarkan acuan formal)","Argumen melingkar (secara konvensional)"],answer:0,hint:"Ad populum = 'kepada rakyat/massa'. Banyak orang percaya = benar?",explanation:"Ad populum: 'Jutaan orang percaya X, maka X benar.'\nPopularitas bukan bukti kebenaran.\nContoh: 'Semua orang pakai produk ini, pasti bagus.'\nJawaban: A."},
{question:"Bacaan: 'Pendidikan STEM tanpa seni menciptakan tenaga kerja yang efisien tapi tidak kreatif.' Sikap penulis: ...",options: ["Kritis terhadap pendidikan STEM yang mengabaikan seni/kreativitas","Mendukung penuh STEM (berdasarkan asumsi dasar; menurut definisi standar)","Menolak semua pendidikan (dalam kerangka teori; menurut pengertian baku)","Seni lebih penting dari sains (dari sudut pandang klasik)","STEM tidak berguna (dalam literatur standar; menurut prinsip dasar)"],answer:0,hint:"'Efisien tapi tidak kreatif' = kritik terhadap ketidakseimbangan.",explanation:"Penulis mengkritik pendidikan STEM yang tidak menyertakan seni.\n'Efisien tapi tidak kreatif' = ada kekurangan.\nSikap: kritis/menyarankan keseimbangan STEM+seni.\nJawaban: A."},
{question:"SINONIM dari 'PRAGMATIS': ...",options: ["Praktis dan berorientasi hasil","Idealis (menurut konsensus ilmiah)","Romantis (dalam arti sempit)","Teoritis (menurut definisi standar)","Filosofis (menurut pengertian baku)"],answer:0,hint:"Pragmatis = fokus pada aspek praktis, bukan teori.",explanation:"Pragmatis: berdasarkan pertimbangan praktis, realistis, berorientasi hasil.\nSinonim: praktis.\nAntonim: idealis, teoritis.\nJawaban: A."},
{question:"ANTONIM dari 'EKSPLISIT': ...",options: ["Implisit (tersirat, tidak langsung disebutkan)","Ekspresif (berdasarkan referensi umum)","Eksklusif (menurut kerangka berpikir umum)","Ekstensif (sesuai teori klasik; dalam kerangka teori)","Eksotis (berdasarkan premis dasar; dari sudut pandang klasik)"],answer:0,hint:"Eksplisit = tersurat/gamblang. Antonimnya = tersirat.",explanation:"Eksplisit: dinyatakan secara jelas, gamblang, tersurat.\nImplisit: tersirat, tidak langsung dinyatakan.\nJawaban: A."},
{question:"Kalimat 'Tangannya panjang' dalam konteks korupsi menggunakan gaya bahasa: ...",options: ["Metonimia (tangan = sifat mencuri)","Hiperbola (sesuai klasifikasi umum)","Personifikasi (berdasarkan teori dasar)","Simile (secara konseptual)","Aliterasi (berdasarkan asumsi dasar)"],answer:0,hint:"Menggunakan ciri fisik untuk menggambarkan sifat = metonimia.",explanation:"'Tangan panjang' = suka mencuri/korupsi.\nMerupakan metonimia: mengganti konsep dengan atribut terkait.\nTangan = instrumen mengambil = pencurian.\nJawaban: A."},
{question:"Teks persuasif berbeda dari teks eksposisi karena: ...",options: ["Tujuannya membujuk/meyakinkan pembaca, bukan sekadar menjelaskan","Tidak menggunakan fakta (dalam batasan konvensional; menurut pandangan mainstream)","Lebih pendek (secara fundamental; berdasarkan referensi umum)","Tidak terstruktur (dalam pemahaman konvensional; dari sudut pandang klasik)","Hanya berisi opini tanpa data (menurut konsensus ilmiah; secara umum)"],answer:0,hint:"Persuasi = membujuk. Eksposisi = menjelaskan/memaparkan.",explanation:"Persuasi: tujuan utamanya membujuk, mempengaruhi, meyakinkan.\nEksposisi: tujuan utamanya menjelaskan, memaparkan informasi.\nKeduanya bisa pakai fakta, tapi tujuan berbeda.\nJawaban: A."},
// --- PENALARAN ANALITIS (31-60) ---
{question:"Dalam debat, menyerang argumen dengan mengatakan 'Kamu masih muda, belum berpengalaman' adalah: ...",options: ["Ad hominem (menyerang pribadi)","Straw man (dalam pengertian luas)","Red herring (dalam definisi teknis)","Slippery slope (dalam konteks umum)","False dilemma (berdasarkan referensi umum)"],answer:0,hint:"Menyerang usia/pengalaman seseorang, bukan isinya.",explanation:"Ad hominem: fokus pada karakter/atribut lawan (usia, pengalaman) bukan substansi argumen.\nJawaban: A."},
{question:"'Jika kita izinkan siswa pakai HP, nanti mereka main game, lalu nilai turun, lalu tidak lulus, lalu pengangguran.' Ini contoh: ...",options: ["Slippery slope (efek bola salju tanpa bukti kuat)","Ad hominem (menurut prinsip dasar; pada konteks konvensional)","Straw man (secara normatif; dalam batasan konvensional)","Begging the question (dari perspektif akademis)","Tu quoque (sesuai klasifikasi umum; dalam pemahaman konvensional)"],answer:0,hint:"Rangkaian sebab-akibat berlebihan tanpa bukti di setiap tahap.",explanation:"Slippery slope: mengklaim satu aksi akan memicu rangkaian peristiwa buruk tanpa bukti memadai.\nHP -> game -> nilai turun -> tidak lulus -> pengangguran (setiap langkah tidak pasti).\nJawaban: A."},
{question:"AMBIGUITAS dalam kalimat 'Anak ibu guru itu pintar' terjadi karena: ...",options: ["Ketidakjelasan struktur: (anak ibu) guru atau anak (ibu guru)","Kata 'pintar' ambigu (berdasarkan acuan formal)","Kata 'anak' ambigu (secara konvensional; dalam pengertian luas)","Tidak ada subjek (pada konteks konvensional; dalam definisi teknis)","Kalimat terlalu panjang (dalam batasan konvensional)"],answer:0,hint:"Modifikasi: siapa yang guru? Ibu atau anak ibu?",explanation:"Ambiguitas struktural:\nInterpretasi 1: Anak (dari ibu guru) itu pintar.\nInterpretasi 2: (Anak ibu) yang guru itu pintar.\nJawaban: A."},
{question:"Dalam argumentasi, 'straw man fallacy' terjadi ketika: ...",options: ["Mendistorsi argumen lawan agar lebih mudah diserang","Menyerang pribadi (dari sudut pandang klasik; dalam teori)","Menggunakan emosi (dalam literatur standar; secara umum)","Banding otoritas (menurut pandangan mainstream; secara klasik)","Argumen melingkar (dalam pengertian luas; menurut kerangka berpikir umum)"],answer:0,hint:"Straw man = membuat 'manusia jerami' (versi lemah) dari argumen lawan.",explanation:"Straw man: memutarbalikkan/menyederhanakan argumen lawan, lalu menyerang versi distorsi itu.\nContoh: A: 'Perlu regulasi emisi.' B: 'Kamu mau tutup semua pabrik?' (distorsi).\nJawaban: A."},
{question:"'Begging the question' (petitio principii) adalah: ...",options: ["Menggunakan kesimpulan sebagai premis (argumen melingkar)","Mengalihkan topik (menurut definisi standar)","Menyerang pribadi (menurut pengertian baku)","Generalisasi (sesuai paradigma tradisional)","Analogi palsu (menurut prinsip dasar; pada konteks konvensional)"],answer:0,hint:"Kesimpulan = premis = kesimpulan = premis... lingkaran.",explanation:"Begging the question: premis mengasumsikan kesimpulan.\nContoh: 'Tuhan ada karena kitab suci bilang begitu, dan kitab suci benar karena dari Tuhan.'\nJawaban: A."},
{question:"Teks: 'Deforestasi Amazon meningkat 34% dalam dekade terakhir meskipun regulasi diperketat.' Dapat DISIMPULKAN: ...",options: ["Regulasi yang ada belum efektif menghentikan deforestasi","Regulasi berhasil (sesuai teori klasik; dalam kerangka teori)","Deforestasi menurun (berdasarkan premis dasar)","Amazon tidak penting (secara terminologis)","Regulasi tidak diperlukan (berdasarkan acuan formal)"],answer:0,hint:"Meskipun regulasi ketat TAPI deforestasi naik = regulasi belum efektif.",explanation:"Konjungsi kontrastif 'meskipun': regulasi ada tapi deforestasi masih naik.\nKesimpulan logis: regulasi belum efektif.\nJawaban: A."},
{question:"Perbedaan FAKTA dan OPINI: 'Indonesia memiliki 17.000+ pulau' vs 'Indonesia adalah negara terindah.' Yang FAKTA: ...",options: ["Indonesia memiliki 17.000+ pulau (dapat diverifikasi)","Indonesia negara terindah (secara konseptual)","Keduanya fakta (berdasarkan asumsi dasar)","Keduanya opini (dalam kerangka teori; menurut pengertian baku)","Tidak bisa dibedakan (dari sudut pandang klasik)"],answer:0,hint:"Fakta = dapat diverifikasi/dibuktikan. Opini = penilaian subjektif.",explanation:"17.000+ pulau: fakta (bisa dihitung/diverifikasi).\n'Terindah': opini (subjektif, tidak bisa diukur universal).\nJawaban: A."},
{question:"EUFEMISME dalam 'beliau telah berpulang ke rahmatullah' menggantikan kata: ...",options: ["Meninggal dunia (penghalusan)","Tidur (dalam pemahaman konvensional)","Pergi (menurut konsensus ilmiah)","Pindah (dalam arti sempit)","Sakit (menurut definisi standar)"],answer:0,hint:"Eufemisme = penghalusan ungkapan kasar/tabu.",explanation:"Eufemisme: mengganti kata yang dianggap kasar/tabu dengan yang lebih halus.\n'Berpulang' = meninggal dunia.\nJawaban: A."},
{question:"'Post hoc ergo propter hoc' adalah kekeliruan logika berupa: ...",options: ["Menganggap sesuatu yang terjadi setelah X pasti disebabkan oleh X","Generalisasi (dalam konteks umum; berdasarkan teori dasar)","Ad hominem (berdasarkan referensi umum; secara konseptual)","Straw man (menurut kerangka berpikir umum; berdasarkan asumsi dasar)","Non sequitur (sesuai teori klasik; dalam kerangka teori)"],answer:0,hint:"Post hoc = setelah ini. Kronologi bukan kausalitas.",explanation:"'Setelah ini, maka karena ini.'\nSesuatu terjadi setelah X bukan berarti disebabkan X.\nContoh: 'Saya pakai kaos merah, lalu menang. Pasti karena kaos merah.'\nJawaban: A."},
{question:"Paragraf induktif memiliki kalimat utama di: ...",options: ["Akhir paragraf (dari khusus ke umum)","Awal paragraf (dari perspektif akademis)","Tengah paragraf (sesuai klasifikasi umum)","Tidak ada kalimat utama (berdasarkan teori dasar)","Di setiap kalimat (secara konseptual)"],answer:0,hint:"Induktif: data/fakta spesifik dulu, kesimpulan umum di akhir.",explanation:"Induktif: khusus -> umum. Kalimat utama di akhir.\nDeduktif: umum -> khusus. Kalimat utama di awal.\nJawaban: A."},
// --- KOSAKATA AKADEMIS (41-80) ---
{question:"EKLEKTIK berarti: ...",options: ["Memilih yang terbaik dari berbagai sumber/gaya","Eksklusif (pada konteks konvensional)","Elektrik (dalam batasan konvensional)","Eksotis (secara fundamental; berdasarkan referensi umum)","Eklips (dalam pemahaman konvensional)"],answer:0,hint:"Eklektik: pandangan/gaya yang mengambil unsur terbaik dari berbagai aliran.",explanation:"Eklektik: menggabungkan elemen terbaik dari berbagai sumber, gaya, atau metode.\nContoh: arsitektur eklektik, pendekatan eklektik.\nJawaban: A."},
{question:"DIKOTOMI berarti: ...",options: ["Pembagian menjadi dua kelompok yang bertentangan","Tiga bagian (menurut pandangan mainstream)","Banyak bagian (dalam pengertian luas)","Penyatuan (dalam definisi teknis; sesuai klasifikasi umum)","Penggabungan (dalam konteks umum; berdasarkan teori dasar)"],answer:0,hint:"Di=dua. Tomia=potongan. Dikotomi=pembagian jadi 2.",explanation:"Dikotomi: pembagian ke dalam dua kelompok yang saling bertentangan.\nContoh: dikotomi baik-buruk, hitam-putih.\nJawaban: A."},
{question:"ANOMALI berarti: ...",options: ["Penyimpangan/ketidaknormalan dari yang biasa","Analogi (sesuai paradigma tradisional)","Anatomi (menurut prinsip dasar; pada konteks konvensional)","Anonim (secara normatif; dalam batasan konvensional)","Anemia (dari perspektif akademis)"],answer:0,hint:"Anomali = sesuatu yang menyimpang dari pola normal.",explanation:"Anomali: sesuatu yang berbeda/menyimpang dari standar, norma, atau pola yang diharapkan.\nContoh: anomali cuaca, anomali data.\nJawaban: A."},
{question:"PARADOKS berarti: ...",options: ["Pernyataan yang tampak kontradiktif tapi mengandung kebenaran","Paralel (secara terminologis; dalam literatur standar)","Parafrase (berdasarkan acuan formal; menurut pandangan mainstream)","Paradigma (secara konvensional; dalam pengertian luas)","Paranoia (pada konteks konvensional; dalam definisi teknis)"],answer:0,hint:"Para=di luar. Doxa=pendapat. Menyalahi pendapat umum tapi benar.",explanation:"Paradoks: pernyataan yang seolah bertentangan/kontradiktif tapi sebenarnya mengandung kebenaran.\nContoh: 'Semakin kau tahu, semakin kau tahu bahwa kau tidak tahu.'\nJawaban: A."},
{question:"HEGEMONI berarti: ...",options: ["Dominasi/penguasaan oleh satu kelompok atas yang lain","Harmoni (dalam kerangka teori; menurut pengertian baku)","Homogen (dari sudut pandang klasik; sesuai paradigma tradisional)","Higienis (dalam literatur standar; menurut prinsip dasar)","Heterogen (menurut pandangan mainstream)"],answer:0,hint:"Hegemoni = dominasi, terutama dalam konteks politik/budaya.",explanation:"Hegemoni: pengaruh, kekuasaan, atau dominasi suatu kelompok/negara atas yang lain.\nIstilah Gramsci: hegemoni budaya.\nJawaban: A."},
{question:"AMBIVALENSI berarti: ...",options: ["Perasaan/sikap yang bertentangan terhadap sesuatu secara bersamaan","Keraguan (dalam arti sempit; berdasarkan premis dasar; dalam definisi teknis)","Kepastian (menurut definisi standar; secara terminologis; dalam pengertian luas)","Kebingungan (menurut pengertian baku; berdasarkan acuan formal)","Ketakutan (sesuai paradigma tradisional; secara konvensional; pada prinsipnya)"],answer:0,hint:"Ambi=dua arah. Valensi=kekuatan. Dua perasaan bertentangan.",explanation:"Ambivalensi: memiliki dua perasaan yang bertentangan (misal cinta dan benci) terhadap objek yang sama secara bersamaan.\nJawaban: A."},
{question:"KOSMOPOLITAN berarti: ...",options: ["Bersifat global, terbuka terhadap berbagai budaya dunia","Lokal (menurut kerangka berpikir umum; berdasarkan asumsi dasar)","Tradisional (sesuai teori klasik; dalam kerangka teori)","Konservatif (berdasarkan premis dasar; dari sudut pandang klasik)","Terisolasi (secara terminologis; dalam literatur standar)"],answer:0,hint:"Kosmo=dunia. Politan=kota. Warga dunia.",explanation:"Kosmopolitan: bersifat mondial/global, terbuka dan akrab dengan berbagai budaya dunia.\nContoh: kota kosmopolitan = Jakarta, New York.\nJawaban: A."},
{question:"FILANTROPI berarti: ...",options: ["Kegiatan amal/kedermawanan untuk kemanusiaan","Filsafat (berdasarkan teori dasar)","Fobia (secara konseptual; dalam arti sempit)","Filateli (berdasarkan asumsi dasar)","Filogeni (dalam kerangka teori; menurut pengertian baku)"],answer:0,hint:"Filo=cinta. Anthropos=manusia. Cinta manusia = dermawan.",explanation:"Filantropi: cinta terhadap sesama manusia yang diwujudkan melalui kegiatan sosial/amal.\nFilantropist = dermawan.\nJawaban: A."},
{question:"ESOTERIS berarti: ...",options: ["Hanya dipahami oleh kalangan terbatas/khusus","Populer (secara fundamental; berdasarkan referensi umum)","Umum (dalam pemahaman konvensional)","Terbuka (menurut konsensus ilmiah)","Sederhana (dalam arti sempit; berdasarkan premis dasar)"],answer:0,hint:"Esoteris: dalam, tersembunyi, hanya untuk yang paham.",explanation:"Esoteris: pengetahuan yang hanya dipahami/diketahui sekelompok kecil orang (kalangan tertentu).\nAntonim: eksoteris (umum).\nJawaban: A."},
{question:"NIHILISME berarti: ...",options: ["Pandangan bahwa hidup tanpa makna/nilai objektif","Optimisme (dalam definisi teknis; sesuai klasifikasi umum)","Idealisme (dalam konteks umum; berdasarkan teori dasar)","Materialisme (berdasarkan referensi umum)","Pragmatisme (menurut kerangka berpikir umum)"],answer:0,hint:"Nihil=tidak ada, kosong. Nihilisme=ketiadaan makna.",explanation:"Nihilisme: pandangan filosofis bahwa kehidupan tidak memiliki makna, tujuan, atau nilai intrinsik.\nNihil (Latin) = tidak ada.\nJawaban: A."},
// --- ANALOGI LANJUTAN (51-80) ---
{question:"ENTOMOLOGI : SERANGGA :: ORNITOLOGI : ...",options:["Burung","Ikan","Reptil","Mamalia","Amfibi"],answer:0,hint:"Entomo=serangga. Ornis=burung. -logi=ilmu.",explanation:"Entomologi: ilmu tentang serangga.\nOrnitologi: ilmu tentang burung.\nJawaban: A."},
{question:"OLIGARKI : SEDIKIT :: DEMOKRASI : ...",options: ["Rakyat/banyak (demos=rakyat)","Satu orang (secara konvensional)","Militer (pada konteks konvensional)","Agama (dalam batasan konvensional)","Kekayaan (secara fundamental)"],answer:0,hint:"Oligarki=pemerintahan oleh sedikit. Demokrasi=pemerintahan oleh rakyat.",explanation:"Oligarki: pemerintahan oleh sekelompok kecil (oligos=sedikit).\nDemokrasi: pemerintahan oleh rakyat (demos=rakyat).\nJawaban: A."},
{question:"SIMFONI : ORKESTRA :: KOREOGRAFI : ...",options:["Tari/balet","Paduan suara","Lukisan","Patung","Fotografi"],answer:0,hint:"Simfoni = komposisi untuk orkestra. Koreografi = komposisi untuk tari.",explanation:"Simfoni: karya musik untuk orkestra.\nKoreografi: karya/susunan gerakan untuk tari.\nJawaban: A."},
{question:"INOVASI : KREATIVITAS :: IMPLEMENTASI : ...",options: ["Eksekusi/pelaksanaan","Imajinasi (secara teknis)","Inspirasi (dalam praktik)","Motivasi (pada dasarnya)","Intuisi (secara normatif)"],answer:0,hint:"Inovasi butuh kreativitas. Implementasi butuh eksekusi.",explanation:"Inovasi = hasil dari kreativitas (menciptakan hal baru).\nImplementasi = wujud dari eksekusi (menerapkan rencana).\nJawaban: A."},
{question:"SINONIM 'KONVERGENSI': ...",options: ["Pemusatan/penyatuan menuju satu titik","Penyebaran (berdasarkan premis dasar)","Pemisahan (secara terminologis)","Pengurangan (berdasarkan acuan formal)","Penambahan (secara konvensional)"],answer:0,hint:"Konvergensi = menuju satu titik. Div ergensi = menyebar.",explanation:"Konvergensi: proses menuju satu titik atau kesepakatan.\nAntonim: divergensi (menyebar ke berbagai arah).\nJawaban: A."},
{question:"ANTAGONIS : PROTAGONIS :: ANTITESIS : ...",options: ["Tesis (pernyataan yang ditentang)","Hipotesis (berdasarkan asumsi dasar)","Sintesis (dalam kerangka teori)","Prognosis (dari sudut pandang klasik)","Diagnosis (dalam literatur standar)"],answer:0,hint:"Antagonis melawan protagonis. Antitesis melawan tesis.",explanation:"Antagonis: yang menentang protagonis.\nAntitesis: yang menentang/kebalikan dari tesis.\nAnti- = melawan.\nJawaban: A."},
{question:"SARKASME berbeda dari IRONI karena: ...",options: ["Sarkasme lebih tajam/menyakitkan, ironi lebih halus","Ironi lebih kasar (menurut konsensus ilmiah)","Sarkasme lebih halus (dalam arti sempit)","Keduanya sama (menurut definisi standar)","Sarkasme bukan gaya bahasa (menurut pengertian baku)"],answer:0,hint:"Sarx (Yunani) = daging. Sarkasme = 'merobek daging' = sangat pedas.",explanation:"Sarkasme: sindiran tajam, pedas, menyakitkan (bermaksud menyerang).\nIroni: pernyataan berlawanan dengan makna sebenarnya (bisa tanpa niat menyerang).\nJawaban: A."},
{question:"PLEONASME dalam 'naik ke atas' terjadi karena: ...",options: ["Pengulangan makna yang tidak perlu (naik sudah berarti ke atas)","Kalimat terlalu panjang (berdasarkan referensi umum)","Tidak ada subjek (menurut kerangka berpikir umum)","Terlalu ringkas (sesuai teori klasik; dalam kerangka teori)","Majas yang indah (berdasarkan premis dasar; dari sudut pandang klasik)"],answer:0,hint:"Pleonasme = mubazir. Naik = ke atas (redundan).",explanation:"Pleonasme: penggunaan kata berlebihan yang bermakna sama.\n'Naik' sudah mengandung makna 'ke atas'.\nContoh lain: 'mundur ke belakang', 'saling tolong-menolong'.\nJawaban: A."},
{question:"MAJAS PERSONIFIKASI dalam kalimat: ...",options: ["'Angin berbisik di telinga' (angin diberi sifat manusia)","'Dia secepat kilat' (sesuai klasifikasi umum)","'Bajunya semerah darah' (berdasarkan teori dasar)","'Bagai pinang dibelah dua' (secara konseptual)","'Harga emas melambung tinggi' (berdasarkan asumsi dasar)"],answer:0,hint:"Personifikasi = memberi sifat/tindakan manusia pada benda mati.",explanation:"Personifikasi: benda mati/hewan diberi sifat manusia.\n'Angin berbisik' = angin diberi kemampuan manusia (berbisik).\nJawaban: A."},
{question:"MAJAS SIMILE ditandai dengan: ...",options: ["Kata pembanding: seperti, bagai, laksana, bak","Tidak ada kata pembanding (dalam batasan konvensional)","Perlawanan makna (secara fundamental)","Pengulangan kata (dalam pemahaman konvensional)","Penghalusan (menurut konsensus ilmiah)"],answer:0,hint:"Simile = perbandingan eksplisit. Metafora = implisit.",explanation:"Simile: perbandingan eksplisit dengan kata pembanding.\nContoh: 'Cantiknya BAGAI bulan purnama.'\nMetafora: perbandingan implisit tanpa kata pembanding.\nContoh: 'Dia BULAN purnama di hidupku.'\nJawaban: A."},
// --- LOGIKA VERBAL LANJUTAN (61-100) ---
{question:"Pernyataan: 'Beberapa dokter adalah peneliti. Semua peneliti menulis jurnal.' Kesimpulan VALID: ...",options:["Beberapa dokter menulis jurnal","Semua dokter menulis jurnal","Semua peneliti adalah dokter","Tidak ada dokter menulis jurnal","Dokter tidak bisa meneliti"],answer:0,hint:"Beberapa A=B. Semua B=C. Maka beberapa A=C.",explanation:"Beberapa dokter = peneliti.\nSemua peneliti menulis jurnal.\nMaka: beberapa dokter menulis jurnal.\nJawaban: A."},
{question:"Kontraposisi dari 'Jika rajin, maka sukses' adalah: ...",options:["Jika tidak sukses, maka tidak rajin","Jika sukses, maka rajin","Jika tidak rajin, maka tidak sukses","Jika rajin, maka tidak sukses","Tidak ada kontraposisi"],answer:0,hint:"Kontraposisi P->Q adalah ~Q->~P.",explanation:"P->Q: rajin->sukses.\nKontraposisi: ~Q->~P = tidak sukses -> tidak rajin.\nKontraposisi selalu ekuivalen dengan conditional asli.\nJawaban: A."},
{question:"'Red herring' dalam debat adalah: ...",options: ["Mengalihkan perhatian ke topik yang tidak relevan","Menyerang pribadi (berdasarkan acuan formal; secara literal)","Argumen melingkar (secara konvensional; menurut prinsip dasar)","Generalisasi (pada konteks konvensional; sesuai paradigma tradisional)","Analogi palsu (dalam batasan konvensional; dalam teori)"],answer:0,hint:"Red herring = ikan hering merah, digunakan untuk mengecoh anjing pelacak.",explanation:"Red herring: memperkenalkan informasi/topik tidak relevan untuk mengalihkan perhatian dari argumen utama.\nContoh: 'Mengapa bahas korupsi? Banyak anak putus sekolah!' (keduanya tidak terkait logic).\nJawaban: A."},
{question:"Teks: 'Data WHO menunjukkan harapan hidup global naik dari 64 ke 73 tahun.' Jenis data ini: ...",options: ["Kuantitatif (berupa angka/numerik yang terukur)","Kualitatif (dari sudut pandang klasik)","Opini (dalam literatur standar; menurut prinsip dasar)","Spekulasi (menurut pandangan mainstream)","Estimasi tanpa dasar (dalam pengertian luas)"],answer:0,hint:"Ada angka spesifik (64, 73) dari sumber terpercaya (WHO).",explanation:"Data kuantitatif: berupa angka-angka terukur.\n64 ke 73 tahun = angka spesifik.\nSumber: WHO (kredibel).\nJawaban: A."},
{question:"'Argumentum ad verecundiam' adalah: ...",options: ["Banding pada otoritas yang tidak relevan","Banding pada emosi (menurut definisi standar)","Banding pada tradisi (menurut pengertian baku)","Banding pada kekuatan (sesuai paradigma tradisional)","Banding pada kasihan (menurut prinsip dasar)"],answer:0,hint:"Ad verecundiam = banding pada rasa hormat/otoritas.",explanation:"Ad verecundiam: menggunakan otoritas/ahli yang tidak relevan sebagai bukti.\nContoh: 'Pemenang Nobel Fisika bilang diet ini bagus' (ahli di bidang lain).\nJawaban: A."},
{question:"Kalimat EFEKTIF harus memenuhi syarat: ...",options: ["Kesepadanan, kehematan, kelogisan, dan ketepatan","Panjang dan berbunga-bunga (sesuai teori klasik)","Menggunakan banyak kata asing (berdasarkan premis dasar)","Selalu menggunakan kalimat majemuk (secara terminologis)","Tanpa predikat (berdasarkan acuan formal)"],answer:0,hint:"Efektif = tepat sasaran. Hemat kata, logis, sepadan, tepat.",explanation:"Syarat kalimat efektif:\n1. Kesepadanan (S-P jelas)\n2. Kehematan (tidak mubazir)\n3. Kelogisan (masuk akal)\n4. Ketepatan (pilihan kata tepat)\nJawaban: A."},
{question:"DENOTASI vs KONOTASI: 'Bunga' dalam 'bunga bank' menggunakan: ...",options: ["Konotasi (makna kiasan/bukan arti sebenarnya)","Denotasi (secara konseptual; dalam arti sempit)","Makna leksikon (berdasarkan asumsi dasar)","Makna gramatikal (dalam kerangka teori)","Makna kontekstual (dari sudut pandang klasik)"],answer:0,hint:"Bunga bank bukan bunga tumbuhan. Ini makna kiasan = konotasi.",explanation:"Denotasi: makna sebenarnya/lugas ('bunga' = bagian tanaman).\nKonotasi: makna kiasan ('bunga bank' = bunga = interest).\nJawaban: A."},
{question:"Dalam penulisan karya ilmiah, OBJEKTIVITAS berarti: ...",options: ["Berdasarkan fakta dan data, bukan opini pribadi","Subjektif dan emosional (dalam pemahaman konvensional)","Tanpa sumber (menurut konsensus ilmiah)","Menggunakan bahasa sehari-hari (dalam arti sempit)","Tidak perlu bukti (menurut definisi standar)"],answer:0,hint:"Objektif = netral, berdasarkan fakta, bisa diverifikasi.",explanation:"Objektivitas dalam karya ilmiah: penyajian berdasarkan fakta, data, dan bukti.\nBukan berdasarkan perasaan, opini, atau bias personal.\nJawaban: A."},
{question:"KOHESI dan KOHERENSI dalam paragraf: ...",options: ["Kohesi = keterkaitan bentuk/kata, Koherensi = keterkaitan makna/ide","Keduanya sama (dalam konteks umum; berdasarkan teori dasar)","Kohesi = makna, Koherensi = bentuk (berdasarkan referensi umum)","Tidak ada perbedaan (menurut kerangka berpikir umum)","Hanya berlaku untuk puisi (sesuai teori klasik; dalam kerangka teori)"],answer:0,hint:"Ko-hesi = melekat bersama (bentuk). Ko-herensi = bersama (isi/makna).",explanation:"Kohesi: keterkaitan antarunsur secara bentuk (konjungsi, referensi, substitusi).\nKoherensi: keterkaitan antarunsur secara makna/isi (ide berkesinambungan).\nJawaban: A."},
{question:"IMPLIKATUR percakapan: A: 'Sudah makan?' B: 'Saya baru dari restoran.' Makna tersirat B: ...",options: ["Sudah makan (implikatur: dari restoran = sudah makan)","Belum makan (dari perspektif akademis; secara fundamental)","Tidak suka makan (sesuai klasifikasi umum)","Restorannya tutup (berdasarkan teori dasar)","Tidak ada makna tersirat (secara konseptual)"],answer:0,hint:"Dari restoran -> implikasi logis: sudah makan.",explanation:"Implikatur: makna yang tersirat/dimaksudkan melebihi apa yang dikatakan.\n'Baru dari restoran' mengimplikasikan sudah makan.\nPrinsip kerja sama Grice.\nJawaban: A."},
// --- KOSAKATA & MAKNA (71-100) ---
{question:"DISRUPSI berarti: ...",options: ["Gangguan radikal yang mengubah tatanan yang ada","Distribusi (pada konteks konvensional)","Diskriminasi (dalam batasan konvensional)","Disfungsi (secara fundamental; berdasarkan referensi umum)","Disposisi (dalam pemahaman konvensional)"],answer:0,hint:"Disrupsi teknologi = teknologi baru mengguncang industri lama.",explanation:"Disrupsi: gangguan/perubahan radikal yang memporakporandakan tatanan/sistem yang sudah mapan.\nContoh: disrupsi digital oleh Gojek, Netflix.\nJawaban: A."},
{question:"RESILIENSI berarti: ...",options: ["Kemampuan bangkit kembali dari kesulitan/tekanan","Resistensi (menurut pandangan mainstream)","Relevansi (dalam pengertian luas; dari perspektif akademis)","Toleransi (dalam definisi teknis; sesuai klasifikasi umum)","Konsistensi (dalam konteks umum; berdasarkan teori dasar)"],answer:0,hint:"Resilient = lentur, bisa kembali ke bentuk semula setelah ditekan.",explanation:"Resiliensi: daya lenting, kemampuan untuk pulih dan beradaptasi setelah menghadapi tekanan/kesulitan.\nJawaban: A."},
{question:"DILEMMA berarti: ...",options: ["Situasi sulit dengan pilihan yang sama-sama tidak menguntungkan","Tiga pilihan (sesuai paradigma tradisional; secara konvensional)","Banyak pilihan (menurut prinsip dasar; pada konteks konvensional)","Pilihan mudah (secara normatif; dalam batasan konvensional)","Tanpa pilihan (dari perspektif akademis; secara fundamental)"],answer:0,hint:"Di=dua. Lemma=proposisi. Dua pilihan sulit.",explanation:"Dilema: situasi yang memaksa memilih antara dua alternatif yang sama-sama tidak diinginkan.\nJawaban: A."},
{question:"PARADIGMA berarti: ...",options: ["Kerangka berpikir/model yang menjadi acuan","Paradoks (secara terminologis; dalam literatur standar)","Paragraf (berdasarkan acuan formal)","Paralel (secara konvensional; dalam pengertian luas)","Parabola (pada konteks konvensional)"],answer:0,hint:"Paradigma = cara pandang fundamental yang menjadi kerangka berpikir.",explanation:"Paradigma: kerangka berpikir, model, atau pola yang diterima sebagai standar.\nParadigm shift (Thomas Kuhn): perubahan revolusioner dalam cara berpikir.\nJawaban: A."},
{question:"STIGMA berarti: ...",options: ["Cap buruk/negatif yang melekat pada seseorang/kelompok","Simbol positif (dalam kerangka teori; menurut pengertian baku)","Penghargaan (dari sudut pandang klasik; sesuai paradigma tradisional)","Pujian (dalam literatur standar; menurut prinsip dasar)","Gelar kehormatan (menurut pandangan mainstream)"],answer:0,hint:"Stigma = tanda aib. Stigmatisasi = pemberian label buruk.",explanation:"Stigma: cap atau label negatif yang dilekatkan pada seseorang/kelompok.\nContoh: stigma terhadap penyandang disabilitas.\nJawaban: A."},
{question:"EUFORIA berarti: ...",options: ["Kegembiraan/kebahagiaan yang berlebihan","Ketakutan berlebihan (dalam arti sempit)","Kesedihan mendalam (menurut definisi standar)","Kemarahan (menurut pengertian baku)","Kebingungan (sesuai paradigma tradisional)"],answer:0,hint:"Eu=baik/bagus. Foria=membawa. Membawa perasaan baik berlebihan.",explanation:"Euforia: rasa gembira, senang, dan optimisme yang berlebihan.\nContoh: euforia kemenangan.\nJawaban: A."},
{question:"APOLOGI berarti: ...",options: ["Pembelaan diri/pembenaran terhadap suatu tindakan","Permintaan maaf (menurut kerangka berpikir umum)","Pujian (sesuai teori klasik; dalam kerangka teori)","Kritikan (berdasarkan premis dasar; dari sudut pandang klasik)","Ucapan terima kasih (secara terminologis)"],answer:0,hint:"Apologi (Yunani) = pidato pembelaan, bukan 'apology' Inggris modern.",explanation:"Apologi: pembelaan diri, pembenaran, pidato untuk membela posisi/tindakan.\nBerbeda dari 'apology' bahasa Inggris modern (= maaf).\nContoh: 'Apologi Socrates' oleh Plato.\nJawaban: A."},
{question:"POLEMIK berarti: ...",options: ["Perdebatan sengit mengenai suatu isu","Perjanjian damai (berdasarkan teori dasar)","Kesepakatan (secara konseptual)","Harmoni (berdasarkan asumsi dasar)","Kolaborasi (dalam kerangka teori)"],answer:0,hint:"Polemik = polemos (perang). Perdebatan tajam/sengit.",explanation:"Polemik: perdebatan tajam dan sengit, terutama mengenai isu publik.\nPolemos (Yunani) = perang.\nJawaban: A."},
{question:"SKEPTISISME berarti: ...",options: ["Sikap meragukan/mempertanyakan segala sesuatu","Percaya tanpa bukti (secara fundamental)","Fanatisme (dalam pemahaman konvensional)","Optimisme berlebihan (menurut konsensus ilmiah)","Pesimisme total (dalam arti sempit)"],answer:0,hint:"Skeptis = ragu, mempertanyakan. Butuh bukti untuk percaya.",explanation:"Skeptisisme: sikap meragukan, mempertanyakan kebenaran suatu klaim sampai ada bukti yang cukup.\nBerbeda dari sinisme (negatif total).\nJawaban: A."},
{question:"UTOPIA vs DISTOPIA: ...",options: ["Utopia = masyarakat ideal sempurna; Distopia = masyarakat mengerikan/buruk","Keduanya positif (dalam definisi teknis; sesuai klasifikasi umum)","Keduanya negatif (dalam konteks umum; berdasarkan teori dasar)","Utopia = nyata, Distopia = fiksi (berdasarkan referensi umum)","Tidak ada perbedaan (menurut kerangka berpikir umum; berdasarkan asumsi dasar)"],answer:0,hint:"U=baik/tidak ada. Topos=tempat. Dis=buruk/tidak.",explanation:"Utopia: tempat/masyarakat ideal sempurna (Thomas More, 1516).\nDistopia: kebalikannya, masyarakat mengerikan/penuh penindasan.\nContoh distopia: 1984 (Orwell), Brave New World (Huxley).\nJawaban: A."},
// --- PEMAHAMAN TEKS KOMPLEKS (81-120) ---
{question:"Jenis teks yang menjelaskan proses terjadinya sesuatu secara kronologis disebut: ...",options:["Eksplanasi","Eksposisi","Argumentasi","Narasi","Deskripsi"],answer:0,hint:"Eksplanasi = menjelaskan proses/mekanisme terjadinya fenomena.",explanation:"Teks eksplanasi: menjelaskan proses terjadinya suatu fenomena secara kronologis/kausal.\nStruktur: pernyataan umum -> deretan penjelas -> interpretasi.\nJawaban: A."},
{question:"Dalam teks akademik, ABSTRAK berfungsi sebagai: ...",options: ["Ringkasan singkat isi keseluruhan karya","Daftar pustaka (secara konvensional)","Kesimpulan (pada konteks konvensional)","Pendahuluan panjang (dalam batasan konvensional)","Lampiran (secara fundamental; berdasarkan referensi umum)"],answer:0,hint:"Abstrak = ringkasan komprehensif dalam 150-300 kata.",explanation:"Abstrak: ringkasan padat yang mencakup tujuan, metode, hasil, dan kesimpulan suatu penelitian/karya ilmiah.\nBiasanya 150-300 kata.\nJawaban: A."},
{question:"TESIS dalam karya argumentatif adalah: ...",options: ["Pernyataan pendapat/posisi utama yang akan dipertahankan","Bukti pendukung (dalam literatur standar; menurut prinsip dasar)","Sanggahan (menurut pandangan mainstream; secara normatif)","Kesimpulan (dalam pengertian luas; dari perspektif akademis)","Latar belakang (dalam definisi teknis; sesuai klasifikasi umum)"],answer:0,hint:"Tesis = thesis statement = klaim utama penulis.",explanation:"Tesis: pernyataan pendapat/posisi utama yang menjadi inti argumen.\nSeluruh esai bertugas membuktikan/mempertahankan tesis ini.\nJawaban: A."},
{question:"REFERENSI ANAFORA dalam teks: 'Dr. Sari melakukan riset. Ia menemukan...' Kata 'Ia' merujuk pada: ...",options: ["Dr. Sari (mengacu pada anteseden sebelumnya)","Orang lain (menurut pengertian baku)","Tidak jelas (sesuai paradigma tradisional)","Riset (menurut prinsip dasar; pada konteks konvensional)","Penemuan (secara normatif; dalam batasan konvensional)"],answer:0,hint:"Anafora: pronomina yang mengacu pada anteseden yang sudah disebutkan.",explanation:"Anafora: rujukan ke belakang (backward reference).\n'Ia' mengacu pada 'Dr. Sari' (anteseden).\nKatafora: rujukan ke depan.\nJawaban: A."},
{question:"Perbedaan KONJUNGSI 'tetapi' dan 'dan': ...",options: ["'Tetapi' menunjukkan pertentangan, 'dan' menunjukkan penambahan","Keduanya sama (berdasarkan premis dasar; dari sudut pandang klasik)","'Dan' menunjukkan pertentangan (secara terminologis)","'Tetapi' menunjukkan sebab-akibat (berdasarkan acuan formal)","Tidak ada perbedaan fungsi (secara konvensional)"],answer:0,hint:"Tetapi/namun/akan tetapi = adversatif. Dan/serta = aditif.",explanation:"'Dan': konjungsi koordinatif aditif (penambahan).\n'Tetapi': konjungsi koordinatif adversatif (pertentangan).\nJawaban: A."},
{question:"BIAS KONFIRMASI dalam membaca berita adalah: ...",options: ["Kecenderungan mencari informasi yang mendukung keyakinan yang sudah ada","Membaca semua sudut pandang (berdasarkan asumsi dasar)","Skeptisisme sehat (dalam kerangka teori; menurut pengertian baku)","Berpikir kritis (dari sudut pandang klasik; sesuai paradigma tradisional)","Analisis objektif (dalam literatur standar; menurut prinsip dasar)"],answer:0,hint:"Konfirmasi = memastikan. Bias konfirmasi = hanya cari yang sesuai.",explanation:"Bias konfirmasi: kecenderungan psikologis untuk mencari, menginterpretasi, dan mengingat informasi yang mendukung keyakinan yang sudah dimiliki.\nJawaban: A."},
{question:"Kalimat 'Saya tidak tidak setuju' menggunakan: ...",options: ["Negasi ganda (double negative) yang bermakna setuju","Pleonasme (menurut konsensus ilmiah; sesuai teori klasik)","Hiperbola (dalam arti sempit; berdasarkan premis dasar)","Litotes (menurut definisi standar; secara terminologis)","Ironi (menurut pengertian baku; berdasarkan acuan formal)"],answer:0,hint:"Tidak + tidak = positif. Tidak-tidak setuju = setuju.",explanation:"Negasi ganda: dua negasi saling meniadakan.\nTidak (tidak setuju) = setuju.\nDalam bahasa baku, ini dihindari karena membingungkan.\nJawaban: A."},
{question:"ARGUMENTASI berbeda dari PERSUASI dalam hal: ...",options: ["Argumentasi menekankan logika/bukti, persuasi menekankan emosi/ajakan","Keduanya identik (berdasarkan referensi umum; secara konseptual)","Argumentasi menggunakan emosi (menurut kerangka berpikir umum)","Persuasi hanya pakai logika (sesuai teori klasik; dalam kerangka teori)","Tidak ada perbedaan (berdasarkan premis dasar; dari sudut pandang klasik)"],answer:0,hint:"Argumen = bukti logis. Persuasi = bujukan (bisa emosi+logika).",explanation:"Argumentasi: berdasarkan penalaran logis dan bukti.\nPersuasi: bertujuan membujuk, bisa menggunakan emosi, ajakan, selain logika.\nJawaban: A."},
{question:"MODUS dalam tata bahasa menunjukkan: ...",options: ["Sikap penutur terhadap tindakan (pernyataan, perintah, harapan)","Waktu kejadian (sesuai klasifikasi umum; dalam pemahaman konvensional)","Jumlah subjek (berdasarkan teori dasar; menurut konsensus ilmiah)","Jenis kata kerja (secara konseptual; dalam arti sempit)","Kelas kata (berdasarkan asumsi dasar; menurut definisi standar)"],answer:0,hint:"Modus: indikatif (pernyataan), imperatif (perintah), subjungtif (harapan).",explanation:"Modus: kategori gramatikal yang mengekspresikan sikap penutur.\nIndikatif: pernyataan fakta.\nImperatif: perintah.\nSubjungtif: harapan, kemungkinan.\nJawaban: A."},
{question:"'False equivalence' adalah kekeliruan logika berupa: ...",options: ["Menyamakan dua hal yang sebenarnya sangat berbeda","Generalisasi (dalam batasan konvensional)","Ad hominem (secara fundamental; berdasarkan referensi umum)","Straw man (dalam pemahaman konvensional)","Red herring (menurut konsensus ilmiah)"],answer:0,hint:"Menyamakan apel dan jeruk, padahal konteks sangat berbeda.",explanation:"False equivalence: memperlakukan dua hal yang tidak setara seolah-olah setara.\nContoh: 'Mencuri roti sama buruknya dengan merampok bank.'\nJawaban: A."},
// --- ANALOGI & PENALARAN (91-130) ---
{question:"METAMORFOSIS : KUPU-KUPU :: REVOLUSI : ...",options: ["Masyarakat/negara (perubahan radikal)","Evolusi (dalam pengertian luas)","Batu (dalam definisi teknis)","Air (dalam konteks umum; berdasarkan teori dasar)","Tanaman (berdasarkan referensi umum)"],answer:0,hint:"Metamorfosis = perubahan bentuk radikal kupu-kupu. Revolusi = perubahan radikal masyarakat.",explanation:"Metamorfosis: perubahan bentuk drastis pada organisme.\nRevolusi: perubahan drastis/radikal pada struktur sosial/politik.\nJawaban: A."},
{question:"VAKSINASI : PENCEGAHAN :: ANTIBIOTIK : ...",options: ["Pengobatan (infeksi bakteri)","Pencegahan (menurut prinsip dasar)","Diagnosis (secara normatif)","Rehabilitasi (dari perspektif akademis)","Deteksi (sesuai klasifikasi umum)"],answer:0,hint:"Vaksin = preventif (sebelum sakit). Antibiotik = kuratif (setelah sakit).",explanation:"Vaksinasi: tindakan pencegahan (preventif).\nAntibiotik: tindakan pengobatan (kuratif).\nJawaban: A."},
{question:"INFLASI : KENAIKAN HARGA :: DEFLASI : ...",options: ["Penurunan harga secara umum","Kenaikan harga lebih cepat","Harga tetap (secara konvensional)","Kenaikan upah (pada konteks konvensional)","Resesi (dalam batasan konvensional)"],answer:0,hint:"In=masuk/naik. De=turun. Flasi=mengembang.",explanation:"Inflasi: kenaikan harga barang/jasa secara umum dan terus-menerus.\nDeflasi: penurunan harga barang/jasa secara umum.\nJawaban: A."},
{question:"SINONIM 'INHERENT': ...",options: ["Melekat secara alami, bawaan","Eksternal (dari sudut pandang klasik)","Sementara (dalam literatur standar)","Buatan (menurut pandangan mainstream)","Superfisial (dalam pengertian luas)"],answer:0,hint:"Inherent = melekat, tidak bisa dipisahkan dari sesuatu.",explanation:"Inherent: melekat secara alami, sudah ada sejak awal, intrinsik.\nContoh: 'Risiko inherent dalam investasi.'\nJawaban: A."},
{question:"ANTONIM 'PROGRESIF': ...",options: ["Konservatif/regresif","Liberal (menurut definisi standar)","Moderat (menurut pengertian baku)","Radikal (sesuai paradigma tradisional)","Revolusioner (pada dasarnya)"],answer:0,hint:"Progresif = maju. Konservatif = mempertahankan yang lama.",explanation:"Progresif: berpandangan maju, mendukung perubahan.\nKonservatif: mempertahankan tradisi/status quo.\nRegresif: mundur ke belakang.\nJawaban: A."},
{question:"Makna kata 'KRITIS' dalam 'pasien dalam kondisi kritis' vs 'berpikir kritis' adalah: ...",options: ["Polisemi (satu kata dengan makna berbeda tergantung konteks)","Homonim (sesuai teori klasik; dalam kerangka teori)","Sinonim (berdasarkan premis dasar; dari sudut pandang klasik)","Antonim (secara terminologis; dalam literatur standar)","Hiponim (berdasarkan acuan formal; menurut pandangan mainstream)"],answer:0,hint:"Satu kata, beberapa makna terkait = polisemi.",explanation:"Polisemi: satu kata memiliki beberapa makna yang masih berhubungan.\n'Kritis' = genting/berbahaya (medis) vs cermat/analitis (berpikir).\nJawaban: A."},
{question:"DIAGNOSIS : PENYAKIT :: FORENSIK : ...",options: ["Bukti kejahatan (analisis ilmiah untuk hukum)","Pengobatan (secara konseptual; dalam arti sempit)","Pencegahan (berdasarkan asumsi dasar)","Rehabilitasi (dalam kerangka teori)","Imunisasi (dari sudut pandang klasik)"],answer:0,hint:"Diagnosis mengidentifikasi penyakit. Forensik mengidentifikasi bukti kejahatan.",explanation:"Diagnosis: identifikasi/penetapan penyakit.\nForensik: analisis bukti ilmiah untuk keperluan hukum/kriminal.\nJawaban: A."},
{question:"EMPATI : SIMPATI :: AKTIF : ...",options: ["Pasif (empati=merasakan langsung, simpati=turut prihatin dari luar)","Agresif (dalam pemahaman konvensional; menurut kerangka berpikir umum)","Reaktif (menurut konsensus ilmiah; sesuai teori klasik)","Proaktif (dalam arti sempit; berdasarkan premis dasar)","Interaktif (menurut definisi standar; secara terminologis)"],answer:0,hint:"Empati = aktif merasakan. Simpati = pasif ikut merasakan.",explanation:"Empati: secara aktif menempatkan diri dalam posisi orang lain.\nSimpati: secara pasif menunjukkan belas kasihan/keprihatinan.\nAnalogi dengan aktif vs pasif.\nJawaban: A."},
{question:"AKRONIM yang sudah menjadi kata umum: ...",options: ["Laser (Light Amplification by Stimulated Emission of Radiation)","Semua singkatan adalah akronim (dalam konteks umum; dalam konteks umum)","Dll (berdasarkan referensi umum; secara konseptual; dalam definisi teknis)","Dsb (menurut kerangka berpikir umum; berdasarkan asumsi dasar)","Hal (sesuai teori klasik; dalam kerangka teori; menurut pandangan mainstream)"],answer:0,hint:"Akronim = singkatan yang dilafalkan sebagai kata.",explanation:"Akronim: singkatan yang dibaca sebagai kata.\nLASER: Light Amplification by Stimulated Emission of Radiation.\nRADAR: Radio Detection and Ranging.\nJawaban: A."},
{question:"DEDUKSI vs INDUKSI: Deduksi dimulai dari: ...",options: ["Premis umum menuju kesimpulan khusus (general -> specific)","Khusus ke umum (dari perspektif akademis; secara fundamental)","Data ke teori (sesuai klasifikasi umum; dalam pemahaman konvensional)","Observasi ke hukum (berdasarkan teori dasar)","Eksperimen ke hipotesis (secara konseptual; dalam arti sempit)"],answer:0,hint:"Deduksi: umum->khusus. Induksi: khusus->umum.",explanation:"Deduksi: dari premis umum ke kesimpulan khusus (top-down).\nInduksi: dari observasi khusus ke generalisasi umum (bottom-up).\nJawaban: A."},
// --- PEMAHAMAN WACANA (101-130) ---
{question:"Kata 'PARADOKS' dalam teks 'Indonesia paradoks: kaya sumber daya tapi banyak rakyat miskin' berarti: ...",options: ["Kontradiksi/pertentangan yang menonjol","Keselarasan (pada konteks konvensional)","Kewajaran (dalam batasan konvensional)","Keindahan (secara fundamental)","Kelaziman (dalam pemahaman konvensional)"],answer:0,hint:"Kaya tapi miskin = kontradiksi = paradoks.",explanation:"Paradoks: pernyataan yang tampak bertentangan.\n'Kaya SDA tapi rakyat miskin' = dua fakta yang seharusnya tidak muncul bersamaan.\nJawaban: A."},
{question:"Fungsi KATA HUBUNG 'oleh karena itu' dalam teks: ...",options: ["Menunjukkan hubungan sebab-akibat (kausal)","Pertentangan (menurut pandangan mainstream)","Perbandingan (dalam pengertian luas)","Penambahan (dalam definisi teknis)","Pengandaian (dalam konteks umum)"],answer:0,hint:"Oleh karena itu = karena alasan sebelumnya, maka...",explanation:"'Oleh karena itu': konjungsi kausal yang menghubungkan sebab (sebelum) dengan akibat (sesudah).\nSejenis: maka, sehingga, akibatnya.\nJawaban: A."},
{question:"ANOTASI dalam membaca akademik adalah: ...",options: ["Catatan/komentar yang ditambahkan pada teks untuk membantu pemahaman","Ringkasan (sesuai paradigma tradisional; secara konvensional; secara literal)","Parafrase (menurut prinsip dasar; pada konteks konvensional; menurut standar)","Kutipan (secara normatif; dalam batasan konvensional; berdasarkan acuan formal)","Daftar pustaka (dari perspektif akademis; secara fundamental; dalam teori)"],answer:0,hint:"Dari 'annotate' = memberi catatan. Annotation = catatan tambahan.",explanation:"Anotasi: catatan, komentar, atau penjelasan yang diberikan pada teks.\nNoted in margins, highlighting, commenting.\nJawaban: A."},
{question:"Teks: 'Literasi digital bukan sekadar kemampuan menggunakan gadget, melainkan kecakapan kritis dalam mengevaluasi informasi.' Implikasi: ...",options: ["Definisi literasi digital lebih luas dari sekadar skill teknis","Literasi digital hanya soal gadget (secara terminologis)","Tidak perlu evaluasi informasi (berdasarkan acuan formal)","Gadget tidak penting (secara konvensional; dalam pengertian luas)","Literasi digital tidak ada (pada konteks konvensional)"],answer:0,hint:"'Bukan sekadar X, melainkan Y' = Y adalah definisi yang lebih luas/tepat.",explanation:"Penulis mengkritik definisi sempit literasi digital (= pakai gadget).\nLiterasi digital = kecakapan kritis mengevaluasi informasi (lebih luas).\nJawaban: A."},
{question:"VERIFIKASI dalam konteks jurnalisme berarti: ...",options: ["Memeriksa kebenaran/keakuratan informasi sebelum dipublikasikan","Menulis cepat (dalam kerangka teori; menurut pengertian baku)","Membagikan berita viral (dari sudut pandang klasik)","Mengutip tanpa sumber (dalam literatur standar; menurut prinsip dasar)","Menerbitkan tanpa edit (menurut pandangan mainstream)"],answer:0,hint:"Veritas (Latin) = kebenaran. Verifikasi = pemeriksaan kebenaran.",explanation:"Verifikasi: proses memastikan kebenaran/keakuratan informasi.\nDalam jurnalisme: wajib sebelum publikasi.\nJawaban: A."},
{question:"MAJAS SINEKDOKE 'pars pro toto' contohnya: ...",options: ["'Setiap KEPALA dikenai biaya Rp50.000' (kepala = orang)","'Matanya tajam' (dalam arti sempit; berdasarkan premis dasar)","'Dia berhidung mancung' (menurut definisi standar)","'Kakinya panjang' (menurut pengertian baku)","'Tangannya terampil' (sesuai paradigma tradisional)"],answer:0,hint:"Pars pro toto = bagian mewakili keseluruhan. Kepala = orang.",explanation:"Sinekdoke pars pro toto: menyebut bagian untuk mewakili keseluruhan.\n'Setiap kepala' = setiap orang.\nTotum pro parte: keseluruhan mewakili bagian.\nJawaban: A."},
{question:"PREMIS dalam argumen tersusun dari: ...",options: ["Pernyataan yang menjadi dasar/alasan untuk menarik kesimpulan","Kesimpulan akhir (menurut kerangka berpikir umum)","Opini tanpa dasar (sesuai teori klasik; dalam kerangka teori)","Pertanyaan retoris (berdasarkan premis dasar; dari sudut pandang klasik)","Sanggahan (secara terminologis; dalam literatur standar)"],answer:0,hint:"Premis = foundation argumen, dari situ ditarik konklusi.",explanation:"Premis: pernyataan yang dianggap benar dan menjadi landasan untuk penarikan kesimpulan.\nArgumen = premis + konklusi.\nJawaban: A."},
{question:"Makna IDIOM 'memeras otak' adalah: ...",options: ["Berpikir sangat keras","Memijat kepala (dalam teori)","Mencuci otak (pada prinsipnya)","Mengoperasi otak (menurut standar)","Membersihkan pikiran"],answer:0,hint:"Idiom: makna tidak bisa ditebak dari kata-katanya secara literal.",explanation:"'Memeras otak' = berpikir keras/sungguh-sungguh.\n'Memeras' secara literal = menekan/mengeluarkan cairan.\nIdiom: ungkapan yang maknanya tidak sesuai makna literal.\nJawaban: A."},
{question:"KALIMAT MAJEMUK SETARA ditandai dengan konjungsi: ...",options: ["Dan, tetapi, atau, sedangkan (menghubungkan klausa setara)","Karena, sehingga, agar (secara fundamental; berdasarkan referensi umum)","Bahwa, supaya (dalam pemahaman konvensional)","Walaupun, meskipun (menurut konsensus ilmiah)","Ketika, sejak (dalam arti sempit; berdasarkan premis dasar)"],answer:0,hint:"Setara = koordinatif. Bertingkat = subordinatif.",explanation:"Majemuk setara: konjungsi koordinatif (dan, tetapi, atau, sedangkan).\nMajemuk bertingkat: konjungsi subordinatif (karena, sehingga, ketika, dll).\nJawaban: A."},
{question:"GENERALISASI TERBURU-BURU (hasty generalization) contohnya: ...",options: ["'Temanku orang Padang suka pedas, pasti semua orang Padang suka pedas'","Kesimpulan dari riset besar (dalam definisi teknis; sesuai klasifikasi umum)","Data statistik nasional (dalam konteks umum; berdasarkan teori dasar)","Survei representatif (berdasarkan referensi umum; secara konseptual)","Meta-analisis 100 studi (menurut kerangka berpikir umum)"],answer:0,hint:"Dari satu/sedikit kasus langsung digeneralisasi = hasty.",explanation:"Hasty generalization: menarik kesimpulan umum dari sampel yang terlalu kecil/tidak representatif.\n1 teman -> semua orang Padang (tidak valid).\nJawaban: A."},
// --- PENALARAN & ANALISIS (131-170) ---
{question:"Dalam kritik sastra, PERSPEKTIF NARATOR 'orang pertama' menggunakan: ...",options: ["Sudut pandang 'aku/saya' (narator adalah tokoh dalam cerita)","Sudut pandang 'dia' (secara normatif; dalam batasan konvensional)","Sudut pandang 'kamu' (dari perspektif akademis)","Tanpa narator (sesuai klasifikasi umum; dalam pemahaman konvensional)","Sudut pandang 'kita' (berdasarkan teori dasar)"],answer:0,hint:"Orang pertama: aku/saya. Orang ketiga: dia/ia.",explanation:"Orang pertama: 'aku/saya' (narator = tokoh, limited perspective).\nOrang ketiga serba tahu: 'dia' (narator tahu semua).\nOrang ketiga terbatas: 'dia' (narator ikut satu tokoh).\nJawaban: A."},
{question:"RETORIKA ARISTOTELES terdiri dari tiga pilar: ...",options: ["Ethos (kredibilitas), Pathos (emosi), Logos (logika)","Hanya logika (secara konvensional; dalam pengertian luas)","Hanya emosi (pada konteks konvensional)","Hanya kredibilitas (dalam batasan konvensional)","Sintaksis, semantik, pragmatik (secara fundamental)"],answer:0,hint:"Aristoteles: pembicara yang baik butuh 3 hal: kredibel, emosional, logis.",explanation:"Ethos: kredibilitas/karakter pembicara.\nPathos: daya tarik emosional.\nLogos: penalaran logis/bukti.\nKetiga pilar ini saling melengkapi.\nJawaban: A."},
{question:"Contoh MAJAS METAFORA: ...",options: ["'Dia adalah bintang kelas kami' (tanpa kata pembanding)","'Dia seperti bintang' (dalam literatur standar; secara literal)","'Dia secepat kilat' (menurut pandangan mainstream; menurut standar)","'Dia bagai bidadari' (dalam pengertian luas; dalam literatur standar)","'Dia laksana mentari' (dalam definisi teknis; dari sudut pandang klasik)"],answer:0,hint:"Metafora = perbandingan langsung tanpa kata seperti/bagai/laksana.",explanation:"Metafora: perbandingan langsung tanpa menggunakan kata pembanding.\n'Dia adalah bintang' (metafora) vs 'Dia seperti bintang' (simile).\nJawaban: A."},
{question:"ETIMOLOGI kata 'FILOSOFI': ...",options: ["Philos (cinta) + Sophia (kebijaksanaan) = cinta kebijaksanaan","Philos + logos (menurut pengertian baku; berdasarkan acuan formal)","Philos + sophy (sesuai paradigma tradisional; secara konvensional)","Bio + logos (menurut prinsip dasar; pada konteks konvensional)","Geo + logos (secara normatif; dalam batasan konvensional)"],answer:0,hint:"Filosofi dari Yunani: philos = cinta, sophia = kebijaksanaan.",explanation:"Philosophia (Yunani): philos (cinta) + sophia (kebijaksanaan).\nFilosof = pecinta kebijaksanaan.\nIstilah dari Pythagoras.\nJawaban: A."},
{question:"FRASE vs KLAUSA: perbedaan utamanya: ...",options: ["Klausa memiliki predikat (S+P), frase tidak","Frase lebih panjang (berdasarkan premis dasar)","Klausa tidak punya kata kerja (secara terminologis)","Keduanya sama (berdasarkan acuan formal)","Frase selalu mengandung predikat (pada dasarnya)"],answer:0,hint:"Klausa = S+P (bisa berdiri sendiri jika lengkap). Frase = tanpa predikat.",explanation:"Frase: kelompok kata tanpa predikat (misal: 'anak kecil').\nKlausa: kelompok kata dengan predikat (misal: 'anak itu bermain').\nKlausa independen = kalimat.\nJawaban: A."},
{question:"Teks: 'Penetrasi internet Indonesia mencapai 77%, namun literasi digital masih rendah.' Hubungan antarfakta: ...",options: ["Paradoks/kontradiksi: akses tinggi tapi kemampuan rendah","Sebab-akibat (berdasarkan asumsi dasar; menurut definisi standar)","Sejalan (dalam kerangka teori; menurut pengertian baku)","Tidak berhubungan (dari sudut pandang klasik)","Kronologis (dalam literatur standar; menurut prinsip dasar)"],answer:0,hint:"'Namun' = pertentangan. Akses 77% tapi literasi rendah = pardoks.",explanation:"'Namun': konjungsi adversatif (pertentangan).\nAkses internet tinggi (77%) TAPI literasi digital rendah.\nIni paradoks: kuantitas =/= kualitas.\nJawaban: A."},
{question:"HOMONIM: 'bisa' dalam 'bisa ular' dan 'bisa datang' adalah: ...",options: ["Dua kata berbeda yang kebetulan sama bentuknya tapi beda makna dan asal","Polisemi (menurut konsensus ilmiah; sesuai teori klasik; berdasarkan acuan formal)","Sinonim (dalam arti sempit; berdasarkan premis dasar; secara terminologis)","Antonim (menurut definisi standar; secara terminologis; berdasarkan premis dasar)","Hipernim (menurut pengertian baku; berdasarkan acuan formal; sesuai teori klasik)"],answer:0,hint:"Homonim = sama bentuk, beda asal dan makna total. Polisemi = satu kata, makna berkembang.",explanation:"Homonim: dua kata berbeda yang kebetulan sama penulisan/pengucapan.\n'Bisa' (racun) dan 'bisa' (mampu/dapat): asal-usul berbeda.\nJawaban: A."},
{question:"KONOTASI POSITIF dari kata 'cerdik': ...",options: ["Pandai, cerdas (konteks positif)","Licik (konteks negatif) (dalam teori)","Bodoh (menurut kerangka berpikir umum)","Malas (sesuai teori klasik)","Lambat (berdasarkan premis dasar)"],answer:0,hint:"'Cerdik' bisa positif (pandai) atau negatif (licik) tergantung konteks.",explanation:"Cerdik:\nKonotasi positif: pandai, tangkas berpikir.\nKonotasi negatif: licik, penuh akal bulus.\nTergantung konteks.\nJawaban: A."},
{question:"KLAUSA SUBORDINATIF dalam: 'Saya belajar KETIKA hujan turun.' Adalah: ...",options: ["'Ketika hujan turun' (klausa anak, tidak bisa berdiri sendiri)","'Saya belajar' (sesuai klasifikasi umum; dalam pemahaman konvensional)","Seluruh kalimat (berdasarkan teori dasar; menurut konsensus ilmiah)","Tidak ada klausa subordinatif (secara konseptual)","'Saya' (berdasarkan asumsi dasar; menurut definisi standar)"],answer:0,hint:"Subordinatif: klausa yang bergantung, ditandai konjungsi subordinatif.",explanation:"'Ketika hujan turun': klausa subordinatif/anak kalimat.\nDitandai konjungsi subordinatif 'ketika'.\nTidak bisa berdiri sendiri sebagai kalimat.\nJawaban: A."},
{question:"INTERTEKSTUALITAS dalam sastra berarti: ...",options: ["Hubungan/rujukan antara satu teks dengan teks lain","Teks yang berdiri sendiri (dalam batasan konvensional)","Tidak ada referensi (secara fundamental)","Plagiarisme (dalam pemahaman konvensional)","Terjemahan (menurut konsensus ilmiah; sesuai teori klasik)"],answer:0,hint:"Inter=antar. Tekstualitas=sifat teks. Hubungan antar teks.",explanation:"Intertekstualitas: konsep bahwa setiap teks dipengaruhi dan terhubung dengan teks-teks lain.\nJulia Kristeva: every text is a mosaic of quotations.\nJawaban: A."},
// --- SOAL CAMPURAN HOTS (141-200) ---
{question:"SINONIM 'SUBSTANSIAL': ...",options: ["Signifikan, penting, berarti","Kecil (dalam pengertian luas)","Tidak penting (dalam definisi teknis)","Dangkal (dalam konteks umum)","Sekilas (berdasarkan referensi umum)"],answer:0,hint:"Substansial = mempunyai substansi/isi yang berarti.",explanation:"Substansial: cukup besar/penting, memiliki substansi.\nContoh: 'perubahan substansial' = perubahan yang signifikan.\nJawaban: A."},
{question:"ANTONIM 'HETEROGEN': ...",options: ["Homogen (seragam, sama jenis)","Lebih beragam (menurut prinsip dasar)","Campuran (secara normatif)","Kompleks (dari perspektif akademis)","Rumit (sesuai klasifikasi umum)"],answer:0,hint:"Hetero=berbeda. Homo=sama. -gen=jenis.",explanation:"Heterogen: terdiri dari jenis-jenis yang berbeda.\nHomogen: terdiri dari jenis yang sama/seragam.\nJawaban: A."},
{question:"KATA BAKU: 'menganalisa' atau 'menganalisis'? ...",options: ["Menganalisis (dari 'analisis' bukan 'analisa')","Menganalisa (berdasarkan acuan formal)","Keduanya benar (secara konvensional)","Keduanya salah (pada konteks konvensional)","Tergantung konteks (dalam batasan konvensional)"],answer:0,hint:"Kata baku: analisis (bukan analisa). me- + analisis = menganalisis.",explanation:"Bentuk baku: analisis (sesuai KBBI).\nme- + analisis = menganalisis.\n'Analisa' dan 'menganalisa' adalah bentuk tidak baku.\nJawaban: A."},
{question:"MAJAS ANTITESIS contohnya: ...",options: ["'Tua-muda, besar-kecil, semua hadir' (mempertentangkan dua hal)","'Dia secepat kilat' (dari sudut pandang klasik; sesuai paradigma tradisional)","'Angin bernyanyi' (dalam literatur standar; menurut prinsip dasar)","'Bagai air di daun talas' (menurut pandangan mainstream)","'Seribu kata tak bermakna' (dalam pengertian luas)"],answer:0,hint:"Anti=melawan. Tesis=pernyataan. Mempertentangkan.",explanation:"Antitesis: gaya bahasa yang mempertentangkan dua hal.\n'Tua-muda, besar-kecil' = pasangan kontras.\nJawaban: A."},
{question:"MAKNA DENOTATIF 'kepala' adalah: ...",options: ["Bagian tubuh teratas yang mengandung otak","Pemimpin (menurut definisi standar)","Bagian atas (menurut pengertian baku)","Awal (sesuai paradigma tradisional)","Tukang (menurut prinsip dasar; pada konteks konvensional)"],answer:0,hint:"Denotatif = makna kamus/literal/sebenarnya.",explanation:"Denotatif: makna sebenarnya/literal.\nKepala (denotatif) = bagian tubuh di atas leher.\nKepala (konotatif) = pemimpin, ketua.\nJawaban: A."},
{question:"Teks: 'Ironinya, negara penghasil kopi terbesar justru mengimpor kopi.' Kata 'ironinya' menunjukkan: ...",options: ["Situasi berlawanan dengan yang diharapkan","Kesedihan (sesuai teori klasik; dalam batasan konvensional)","Kebahagiaan (berdasarkan premis dasar; secara literal)","Kenetralan (secara terminologis; secara konvensional)","Persetujuan (berdasarkan acuan formal; pada prinsipnya)"],answer:0,hint:"Ironi = berlawanan dengan harapan/logika. Penghasil tapi mengimpor.",explanation:"Ironi situasional: hasil (mengimpor kopi) berlawanan dengan yang diharapkan dari penghasil kopi terbesar.\nJawaban: A."},
{question:"SEMANTIK mempelajari: ...",options: ["Makna kata dan kalimat dalam bahasa","Bunyi bahasa (secara konseptual)","Pembentukan kata (berdasarkan asumsi dasar)","Susunan kalimat (dalam kerangka teori)","Penggunaan bahasa dalam konteks"],answer:0,hint:"Semantik = ilmu makna. Fonetik=bunyi. Morfologi=kata. Sintaksis=kalimat.",explanation:"Semantik: cabang linguistik yang mempelajari makna.\nFonologi: bunyi. Morfologi: kata. Sintaksis: kalimat.\nPragmatik: makna dalam konteks.\nJawaban: A."},
{question:"PRAGMATIK mempelajari: ...",options: ["Makna bahasa dalam konteks penggunaannya","Bunyi (dalam pemahaman konvensional)","Bentuk kata (menurut konsensus ilmiah)","Makna literal (dalam arti sempit)","Sejarah bahasa (menurut definisi standar)"],answer:0,hint:"Pragmatik = bahasa dalam konteks. Semantik = makna tanpa konteks.",explanation:"Pragmatik: mempelajari bagaimana konteks mempengaruhi makna.\nTermasuk implikatur, tindak tutur, deiksis.\nBerbeda dari semantik (makna tanpa konteks).\nJawaban: A."},
{question:"DEIKSIS dalam 'SINI, SEKARANG, SAYA' bersifat: ...",options: ["Tergantung konteks (siapa bicara, kapan, di mana)","Tetap (dalam konteks umum; berdasarkan teori dasar)","Universal (berdasarkan referensi umum)","Tidak bermakna (menurut kerangka berpikir umum)","Literal (sesuai teori klasik; dalam kerangka teori)"],answer:0,hint:"Deiksis: makna berubah tergantung siapa/kapan/di mana diucapkan.",explanation:"Deiksis: ungkapan yang maknanya tergantung konteks.\nSini = tergantung lokasi pembicara.\nSekarang = tergantung waktu bicara.\nSaya = tergantung siapa bicara.\nJawaban: A."},
{question:"TINDAK TUTUR ILOKUSI dalam 'Ruangannya panas sekali' yang bermaksud meminta AC dinyalakan adalah: ...",options: ["Direktif tidak langsung (meminta secara tidak langsung)","Komisif (dari perspektif akademis; secara fundamental)","Ekspresif (sesuai klasifikasi umum; dalam pemahaman konvensional)","Deklaratif (berdasarkan teori dasar; menurut konsensus ilmiah)","Representatif (secara konseptual; dalam arti sempit)"],answer:0,hint:"Mengatakan satu hal tapi bermaksud lain = tindak tutur tidak langsung.",explanation:"Tindak tutur ilokusi: maksud di balik ujaran.\n'Panas sekali' secara literal = konstatif (menyatakan fakta).\nMaksud sebenarnya = direktif (meminta nyalakan AC).\nIni tindak tutur tidak langsung.\nJawaban: A."},
{question:"GAYA BAHASA REPETISI contohnya: ...",options: ["'Merdeka! Merdeka! Merdeka!' (pengulangan kata untuk penekanan)","'Dia secepat kilat' (pada konteks konvensional; dalam definisi teknis)","'Angin bernyanyi' (dalam batasan konvensional; dalam konteks umum)","'Bagai air dan minyak' (secara fundamental; berdasarkan referensi umum)","'Ibarat langit dan bumi' (dalam pemahaman konvensional)"],answer:0,hint:"Repetisi = pengulangan. Untuk efek retorika/penekanan.",explanation:"Repetisi: pengulangan kata/frase untuk penekanan.\n'Merdeka! Merdeka! Merdeka!' = pengulangan 3x.\nEfek: penekanan emosional.\nJawaban: A."},
{question:"ALUSI dalam sastra adalah: ...",options: ["Rujukan tidak langsung pada teks/peristiwa/tokoh terkenal","Ilusi optik (menurut pandangan mainstream; secara normatif)","Delusi (dalam pengertian luas; dari perspektif akademis)","Kontradiksi (dalam definisi teknis; sesuai klasifikasi umum)","Ironi (dalam konteks umum; berdasarkan teori dasar)"],answer:0,hint:"Alusi = sindiran/rujukan pada sesuatu yang terkenal tanpa menyebut langsung.",explanation:"Alusi: rujukan atau sindiran tidak langsung pada karya sastra, sejarah, mitologi, atau peristiwa terkenal.\nContoh: 'Dia Pahlawan Kesiangan' (alusi ke istilah lazim).\nJawaban: A."},
{question:"FUNGSI KONJUNGSI 'meskipun' dalam kalimat adalah: ...",options: ["Menunjukkan hubungan konsesif (mengalah: meski X, tetap Y)","Kausal (sesuai paradigma tradisional; secara konvensional)","Temporal (menurut prinsip dasar; pada konteks konvensional)","Aditif (secara normatif; dalam batasan konvensional)","Koordinatif (dari perspektif akademis; secara fundamental)"],answer:0,hint:"Meskipun/walaupun/kendati = konsesif (mengalah).",explanation:"Konsesif: 'meskipun X, Y tetap terjadi.'\nX seharusnya menghalangi Y, tapi Y tetap terjadi.\nKonjungsi: meskipun, walaupun, kendati, biarpun.\nJawaban: A."},
{question:"Bacaan: 'AI generatif menantang definisi kreativitas manusia.' Ini contoh pernyataan: ...",options: ["Provokatif/kontroversial yang mengundang perdebatan","Faktual sederhana (secara terminologis)","Netral (berdasarkan acuan formal; menurut pandangan mainstream)","Tidak berbobot (secara konvensional; dalam pengertian luas)","Deskriptif murni (pada konteks konvensional)"],answer:0,hint:"'Menantang definisi' = mempertanyakan = provokatif/mengundang debat.",explanation:"Pernyataan ini provokatif: mengajukan gagasan bahwa AI bisa mengubah pemahaman kita tentang kreativitas.\nMemicu perdebatan filosofis: apakah output AI = kreatif?\nJawaban: A."},
{question:"JARGON dalam bidang hukum contohnya: ...",options: ["Yurisprudensi, eksekusi, putusan sela","Kecepatan cahaya (dalam kerangka teori)","Mutasi gen (dari sudut pandang klasik)","Inflasi (dalam literatur standar)","Algoritma (menurut pandangan mainstream)"],answer:0,hint:"Jargon = istilah teknis khusus suatu bidang.",explanation:"Jargon: terminologi khusus yang digunakan dalam bidang profesi tertentu.\nHukum: yurisprudensi, eksekusi, putusan sela, dakwaan, tuntutan.\nJawaban: A."},
{question:"'Circular reasoning' dalam argumen: ...",options: ["Kesimpulan digunakan sebagai premis (argumen berputar-putar)","Argumen lurus (dalam arti sempit; berdasarkan premis dasar)","Argumen kuat (menurut definisi standar; secara terminologis)","Penalaran induktif (menurut pengertian baku; berdasarkan acuan formal)","Penalaran deduktif (sesuai paradigma tradisional)"],answer:0,hint:"Circular = melingkar. Premis -> kesimpulan -> premis lagi.",explanation:"Circular reasoning: A benar karena B, B benar karena A.\nTidak ada bukti independen.\nSama dengan 'begging the question'.\nJawaban: A."},
{question:"Kata 'ELABORASI' berarti: ...",options: ["Pengembangan secara rinci dan mendalam","Penyederhanaan (menurut kerangka berpikir umum)","Pengurangan (sesuai teori klasik)","Peringkasan (berdasarkan premis dasar)","Penghapusan (secara terminologis)"],answer:0,hint:"Elaborasi = menjelaskan lebih detail, menguraikan lebih lanjut.",explanation:"Elaborasi: proses mengembangkan/menguraikan sesuatu secara lebih rinci dan mendalam.\nDari 'elaborate' = rinci, detail.\nJawaban: A."},
{question:"'FALLACY OF COMPOSITION' terjadi ketika: ...",options: ["Menganggap apa yang berlaku untuk bagian berlaku juga untuk keseluruhan","Menganggap keseluruhan berlaku untuk bagian (berdasarkan teori dasar)","Menyerang pribadi (secara konseptual; dalam arti sempit; menurut kerangka berpikir umum)","Argumen melingkar (berdasarkan asumsi dasar; menurut definisi standar)","Generalisasi (dalam kerangka teori; menurut pengertian baku; dalam konteks umum)"],answer:0,hint:"Composition: parts -> whole. Pemain hebat -> tim hebat (belum tentu).",explanation:"Fallacy of composition: menyimpulkan bahwa sifat bagian pasti berlaku untuk keseluruhan.\n'Setiap pemain bagus' =/= 'tim bagus' (belum tentu).\nJawaban: A."},
{question:"NUANSA makna antara 'rumah', 'wisma', dan 'istana': ...",options: ["Perbedaan derajat/tingkat kemewahan (dari biasa ke mewah)","Semua sama (secara fundamental; berdasarkan referensi umum)","Tidak ada perbedaan (dalam pemahaman konvensional)","Hanya ukuran berbeda (menurut konsensus ilmiah)","Hanya warna berbeda (dalam arti sempit; berdasarkan premis dasar)"],answer:0,hint:"Rumah (biasa) < wisma (lebih bagus) < istana (sangat mewah).",explanation:"Nuansa makna: perbedaan halus dalam derajat/gradasi.\nRumah: tempat tinggal biasa.\nWisma: lebih terhormat/bagus.\nIstana: sangat besar/mewah (raja).\nJawaban: A."},
{question:"KATA TUGAS dalam bahasa Indonesia meliputi: ...",options: ["Preposisi, konjungsi, partikel, interjeksi (kata fungsi gramatikal)","Nomina dan verba (dalam definisi teknis; sesuai klasifikasi umum)","Hanya konjungsi (dalam konteks umum; berdasarkan teori dasar; pada prinsipnya)","Hanya preposisi (berdasarkan referensi umum; secara konseptual; dalam teori)","Kata kerja dan kata sifat (menurut kerangka berpikir umum; berdasarkan premis dasar)"],answer:0,hint:"Kata tugas = function words. Bukan kata isi/konten.",explanation:"Kata tugas (function words): preposisi (di, ke, dari), konjungsi (dan, tetapi), partikel (lah, kah), interjeksi (wah, aduh).\nBerbeda dari kata isi (nomina, verba, adjektiva).\nJawaban: A."},
]);
